const URL = 'https://practice-papers.onrender.com/subject/addSubject'
const Token = localStorage.getItem('O_authDB')

const addSubject = (data, setserverOperationError, setServerOperationLoading, setAllSubject) => {
    setServerOperationLoading(true)
    fetch(URL, {
        method: 'post',
        headers: {
            'Content-Type': 'application/json',
            'authrization': `pracYas09${Token}`
        },
        body: JSON.stringify(data)
    })
        .then((response) => response.json())
        .then((responseJson) => {
            if (responseJson.message === 'success') {
                document.querySelector('.add-subject-popup').classList.replace('d-flex', 'd-none');
                setServerOperationLoading(false)
                setserverOperationError(null)
                setAllSubject(responseJson.allSubjects)
            } else {
                setserverOperationError(responseJson.message)
                setServerOperationLoading(false)
            }
        })
        .catch((error) => {
            setserverOperationError(error.message)
            setServerOperationLoading(false)
        });
}

export default addSubject;
